73	impl<T> FifoChannelHandler<T> {
74	    /// Attempt to fetch an incoming value from the channel associated with this receiver, returning
75	    /// an error if the channel is empty or if all senders have been dropped.
76	    ///
77	    /// If the channel is empty, this will return [`None`].
78	    pub fn try_recv(&self) -> ZResult<Option<T>> {
79	        match self.0.try_recv() {
80	            Ok(value) => Ok(Some(value)),
81	            Err(flume::TryRecvError::Empty) => Ok(None),
82	            Err(err) => Err(err.into()),
83	        }
