87	    /// error if all senders have been dropped.
88	    pub fn recv(&self) -> ZResult<T> {
89	        self.0.recv().map_err(Into::into)
90	    }
91	
92	    /// Wait for an incoming value from the channel associated with this receiver, returning an
93	    /// error if all senders have been dropped or the deadline has passed.
94	    ///
95	    /// If the deadline has expired, this will return [`None`].
96	    pub fn recv_deadline(&self, deadline: Instant) -> ZResult<Option<T>> {
97	        match self.0.recv_deadline(deadline) {
98	            Ok(value) => Ok(Some(value)),
99	            Err(flume::RecvTimeoutError::Timeout) => Ok(None),
100	            Err(err) => Err(err.into()),
101	        }
102	    }
103	
104	    /// Wait for an incoming value from the channel associated with this receiver, returning an
105	    /// error if all senders have been dropped or the timeout has expired.
106	    ///
107	    /// If the timeout has expired, this will return [`None`].
108	    pub fn recv_timeout(&self, duration: Duration) -> ZResult<Option<T>> {
109	        match self.0.recv_timeout(duration) {
110	            Ok(value) => Ok(Some(value)),
111	            Err(flume::RecvTimeoutError::Timeout) => Ok(None),
112	            Err(err) => Err(err.into()),
113	        }
114	    }
