119	        Iter(self.0.iter())
120	    }
121	
122	    /// A non-blocking iterator over the values received on the channel that finishes iteration when
123	    /// all senders have been dropped or the channel is empty.
124	    pub fn try_iter(&self) -> TryIter<'_, T> {
125	        TryIter(self.0.try_iter())
126	    }
