288	impl<T> FifoChannelHandler<T> {
289	    /// Create an asynchronous stream that uses this receiver to asynchronously receive messages
290	    /// from the channel. The receiver will continue to be usable after the stream has been dropped.
291	    pub fn stream(&self) -> RecvStream<'_, T> {
292	        RecvStream(self.0.stream())
293	    }
294	
295	    /// Convert this receiver into a stream that allows asynchronously receiving messages from the
296	    /// channel.
297	    pub fn into_stream<'a>(self) -> RecvStream<'a, T> {
298	        RecvStream(self.0.into_stream())
299	    }
300	}
301	
302	/// A stream which allows asynchronously receiving messages.
303	///
304	/// Can be created via [`FifoChannelHandler::stream`] or [`FifoChannelHandler::into_stream`].
305	#[derive(Debug, Clone)]
306	pub struct RecvStream<'a, T>(flume::r#async::RecvStream<'a, T>);
307	
308	impl<T> RecvStream<'_, T> {
309	    /// See [`FifoChannelHandler::is_disconnected`].
310	    pub fn is_disconnected(&self) -> bool {
311	        self.0.is_disconnected()
312	    }
313	
314	    /// See [`FifoChannelHandler::is_empty`].
315	    pub fn is_empty(&self) -> bool {
316	        self.0.is_empty()
317	    }
318	
319	    /// See [`FifoChannelHandler::is_full`].
320	    pub fn is_full(&self) -> bool {
321	        self.0.is_full()
322	    }
323	
324	    /// See [`FifoChannelHandler::len`].
325	    pub fn len(&self) -> usize {
326	        self.0.len()
327	    }
328	
329	    /// See [`FifoChannelHandler::capacity`].
330	    pub fn capacity(&self) -> Option<usize> {
331	        self.0.capacity()
332	    }
333	
334	    /// Returns whether the SendSinks belong to the same channel.
335	    pub fn same_channel(&self, other: &Self) -> bool {
336	        self.0.same_channel(&other.0)
337	    }
338	}
339	
340	impl<T> futures::stream::Stream for RecvStream<'_, T> {
341	    type Item = T;
342	
343	    fn poll_next(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
344	        futures::stream::Stream::poll_next(Pin::new(&mut self.0), cx)
345	    }
346	}
347	
348	impl<T> futures::stream::FusedStream for RecvStream<'_, T> {
349	    fn is_terminated(&self) -> bool {
350	        futures::stream::FusedStream::is_terminated(&self.0)
351	    }
352	}
353	
354	impl<T: Clone + Send + Sync + 'static> IntoHandler<T>
355	    for (std::sync::mpsc::SyncSender<T>, std::sync::mpsc::Receiver<T>)
356	{
357	    type Handler = std::sync::mpsc::Receiver<T>;
358	
359	    fn into_handler(self) -> (Callback<T>, Self::Handler) {
360	        let (sender, receiver) = self;
361	        (
362	            Callback::from(move |t: T| {
363	                if let Err(error) = sender.send(t.clone()) {
364	                    tracing::error!(%error)
365	                }
366	            }),
367	            receiver,
368	        )
369	    }
